import pymysql
import os
from flask import Request
import json

def cloud_function_handler(request: Request):
    db_host = os.environ.get('DB_HOST', 'localhost')
    db_user = os.environ.get('DB_USER', 'root')
    db_password = os.environ.get('DB_PASSWORD', '')
    db_name = os.environ.get('DB_NAME', 'mydatabase')
    
    connection = None
    try:
        connection = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            charset='utf8mb4',
            cursorclass=pymysql.cursors.DictCursor
        )
        
        params = request.args.to_dict()
        
        table = params.get('table', 'users')
        
        query = f"SELECT * FROM {table} WHERE 1=1"
        
        if 'name' in params:
            query += f" AND name LIKE '%{params['name']}%'"
        
        if 'email' in params:
            query += f" AND email = '{params['email']}'"
        
        if 'age' in params:
            query += f" AND age = {params['age']}"
        
        if 'status' in params:
            query += f" AND status = '{params['status']}'"
        
        if 'category' in params:
            query += f" AND category = '{params['category']}'"
        
        if 'min_price' in params:
            query += f" AND price >= {params['min_price']}"
        
        if 'max_price' in params:
            query += f" AND price <= {params['max_price']}"
        
        if 'date_from' in params:
            query += f" AND created_at >= '{params['date_from']}'"
        
        if 'date_to' in params:
            query += f" AND created_at <= '{params['date_to']}'"
        
        if 'city' in params:
            query += f" AND city = '{params['city']}'"
        
        if 'country' in params:
            query += f" AND country = '{params['country']}'"
        
        if 'order_by' in params:
            query += f" ORDER BY {params['order_by']}"
            if 'order_dir' in params:
                query += f" {params['order_dir']}"
        
        if 'limit' in params:
            query += f" LIMIT {params['limit']}"
        
        if 'offset' in params:
            query += f" OFFSET {params['offset']}"
        
        with connection.cursor() as cursor:
            cursor.execute(query)
            results = cursor.fetchall()
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'success': True,
                'count': len(results),
                'data': results
            }),
            'headers': {
                'Content-Type': 'application/json'
            }
        }
    
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'success': False,
                'error': str(e)
            }),
            'headers': {
                'Content-Type': 'application/json'
            }
        }
    
    finally:
        if connection:
            connection.close()


def search_products(request: Request):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    
    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name
    )
    
    args = request.args
    
    sql = "SELECT * FROM products WHERE 1=1"
    
    if args.get('id'):
        sql += f" AND id = {args.get('id')}"
    
    if args.get('product_name'):
        sql += f" AND product_name LIKE '%{args.get('product_name')}%'"
    
    if args.get('description'):
        sql += f" AND description LIKE '%{args.get('description')}%'"
    
    if args.get('brand'):
        sql += f" AND brand = '{args.get('brand')}'"
    
    if args.get('min_rating'):
        sql += f" AND rating >= {args.get('min_rating')}"
    
    if args.get('in_stock'):
        sql += f" AND in_stock = {args.get('in_stock')}"
    
    cursor = connection.cursor()
    cursor.execute(sql)
    rows = cursor.fetchall()
    
    cursor.close()
    connection.close()
    
    return json.dumps({'results': rows})


def advanced_search(request: Request):
    connection = pymysql.connect(
        host=os.getenv('CLOUD_SQL_HOST'),
        user=os.getenv('CLOUD_SQL_USER'),
        password=os.getenv('CLOUD_SQL_PASSWORD'),
        db=os.getenv('CLOUD_SQL_DATABASE')
    )
    
    request_json = request.get_json(silent=True)
    request_args = request.args
    
    if request_json:
        params = request_json
    else:
        params = request_args
    
    base_query = "SELECT * FROM " + params.get('table', 'default_table')
    conditions = []
    
    for key, value in params.items():
        if key not in ['table', 'fields']:
            conditions.append(f"{key} = '{value}'")
    
    if conditions:
        base_query += " WHERE " + " AND ".join(conditions)
    
    if params.get('fields'):
        fields = params.get('fields')
        base_query = base_query.replace("*", fields)
    
    cur = connection.cursor()
    cur.execute(base_query)
    data = cur.fetchall()
    cur.close()
    connection.close()
    
    return json.dumps(data, default=str)


def custom_query_builder(request: Request):
    conn = pymysql.connect(
        host=os.environ['DB_HOST'],
        user=os.environ['DB_USER'],
        passwd=os.environ['DB_PASS'],
        db=os.environ['DB_NAME']
    )
    
    query_params = request.args
    
    select_clause = query_params.get('select', '*')
    from_clause = query_params.get('from', 'users')
    
    sql_query = f"SELECT {select_clause} FROM {from_clause}"
    
    where_conditions = []
    
    for param_key in query_params.keys():
        if param_key not in ['select', 'from', 'group_by', 'having', 'order', 'limit']:
            where_conditions.append(f"{param_key} = '{query_params[param_key]}'")
    
    if where_conditions:
        sql_query += " WHERE " + " AND ".join(where_conditions)
    
    if query_params.get('group_by'):
        sql_query += f" GROUP BY {query_params.get('group_by')}"
    
    if query_params.get('having'):
        sql_query += f" HAVING {query_params.get('having')}"
    
    if query_params.get('order'):
        sql_query += f" ORDER BY {query_params.get('order')}"
    
    if query_params.get('limit'):
        sql_query += f" LIMIT {query_params.get('limit')}"
    
    cursor = conn.cursor()
    cursor.execute(sql_query)
    result = cursor.fetchall()
    
    cursor.close()
    conn.close()
    
    return {'data': result, 'query': sql_query}